// ============================================================
// FLOWSTATE — Token Auto-Refresh
// Runs on the 1st of each month at 10am.
// Refreshes Instagram + Threads long-lived tokens via Meta API.
// Saves to tokens.json — approval workflow reads this on every
// run, so no n8n restart is needed after a refresh.
// ============================================================
const fs   = require('fs');
const path = require('path');

const SCRIPTS_DIR = process.env.SCRIPTS_DIR || '/data/scripts';
const TOKENS_FILE = path.join(SCRIPTS_DIR, 'tokens.json');

const TWILIO_SID   = process.env.TWILIO_ACCOUNT_SID   || $env.TWILIO_ACCOUNT_SID;
const TWILIO_TOKEN = process.env.TWILIO_AUTH_TOKEN     || $env.TWILIO_AUTH_TOKEN;
const TWILIO_FROM  = process.env.TWILIO_WHATSAPP_FROM  || $env.TWILIO_WHATSAPP_FROM || 'whatsapp:+14155238886';
const TWILIO_TO    = process.env.TWILIO_WHATSAPP_TO    || $env.TWILIO_WHATSAPP_TO;

async function sendWhatsApp(msg) {
  const url   = 'https://api.twilio.com/2010-04-01/Accounts/' + TWILIO_SID + '/Messages.json';
  const creds = Buffer.from(TWILIO_SID + ':' + TWILIO_TOKEN).toString('base64');
  await fetch(url, {
    method:  'POST',
    headers: { 'Authorization': 'Basic ' + creds, 'Content-Type': 'application/x-www-form-urlencoded' },
    body:    new URLSearchParams({ From: TWILIO_FROM, To: TWILIO_TO, Body: msg }).toString(),
  });
}

// ── Read current tokens (prefer tokens.json over env vars) ──────────────────
let currentIG = process.env.INSTAGRAM_ACCESS_TOKEN || '';
let currentTH = process.env.THREADS_ACCESS_TOKEN   || '';
try {
  if (fs.existsSync(TOKENS_FILE)) {
    const stored = JSON.parse(fs.readFileSync(TOKENS_FILE, 'utf8'));
    if (stored.instagram_access_token) currentIG = stored.instagram_access_token;
    if (stored.threads_access_token)   currentTH = stored.threads_access_token;
    console.log('[TokenRefresh] Loaded current tokens from', TOKENS_FILE);
  }
} catch(e) { console.log('[TokenRefresh] Could not read tokens.json:', e.message); }

const results = { ig: null, th: null, errors: [] };

// ── Refresh Instagram token ──────────────────────────────────────────────────
if (currentIG) {
  try {
    const res  = await fetch('https://graph.instagram.com/refresh_access_token?grant_type=ig_refresh_token&access_token=' + currentIG);
    const data = await res.json();
    if (data.access_token) {
      results.ig = data.access_token;
      console.log('[TokenRefresh] Instagram: refreshed. Expires in ~', Math.round((data.expires_in || 5183944) / 86400), 'days');
    } else {
      const errMsg = data.error ? data.error.message : JSON.stringify(data).substring(0, 150);
      results.errors.push('Instagram: ' + errMsg);
      console.log('[TokenRefresh] Instagram error:', errMsg);
    }
  } catch(e) {
    results.errors.push('Instagram fetch error: ' + e.message);
  }
} else {
  results.errors.push('INSTAGRAM_ACCESS_TOKEN not set — skipped');
}

// ── Refresh Threads token ────────────────────────────────────────────────────
if (currentTH) {
  try {
    const res  = await fetch('https://graph.threads.net/refresh_access_token?grant_type=th_refresh_token&access_token=' + currentTH);
    const data = await res.json();
    if (data.access_token) {
      results.th = data.access_token;
      console.log('[TokenRefresh] Threads: refreshed. Expires in ~', Math.round((data.expires_in || 5183944) / 86400), 'days');
    } else {
      const errMsg = data.error ? data.error.message : JSON.stringify(data).substring(0, 150);
      results.errors.push('Threads: ' + errMsg);
      console.log('[TokenRefresh] Threads error:', errMsg);
    }
  } catch(e) {
    results.errors.push('Threads fetch error: ' + e.message);
  }
} else {
  results.errors.push('THREADS_ACCESS_TOKEN not set — skipped');
}

// ── Save refreshed tokens to tokens.json ────────────────────────────────────
const expiresApprox = new Date(Date.now() + 60 * 24 * 60 * 60 * 1000).toDateString();
const tokensData = {
  instagram_access_token: results.ig || currentIG,
  threads_access_token:   results.th || currentTH,
  last_refreshed:         new Date().toISOString(),
  expires_approximately:  expiresApprox,
};
fs.writeFileSync(TOKENS_FILE, JSON.stringify(tokensData, null, 2));
console.log('[TokenRefresh] Saved to', TOKENS_FILE);

// ── Send WhatsApp notification ───────────────────────────────────────────────
const igLine = results.ig ? '\u2705 Instagram token refreshed' : '\u26a0\ufe0f Instagram: ' + (results.errors.find(e => e.startsWith('Instagram')) || 'failed');
const thLine = results.th ? '\u2705 Threads token refreshed'   : '\u26a0\ufe0f Threads: '   + (results.errors.find(e => e.startsWith('Threads'))   || 'failed');

const errBlock = results.errors.length > 0
  ? '\n\n\u26a0\ufe0f Errors:\n' + results.errors.join('\n')
  : '';

const msg = [
  '\ud83d\udd11 FLOWSTATE \u2014 Tokens Auto-Refreshed',
  '',
  igLine,
  thLine,
  '',
  'Valid until: ~' + expiresApprox,
  '',
  'No action needed \u2014 tokens load automatically on the next approval.'
  + errBlock,
].join('\n');

await sendWhatsApp(msg);
console.log('[TokenRefresh] Done. IG:', results.ig ? 'OK' : 'FAILED', '| Threads:', results.th ? 'OK' : 'FAILED');

return [{
  action:    'token_refresh_complete',
  instagram: results.ig ? 'refreshed' : 'failed',
  threads:   results.th ? 'refreshed' : 'failed',
  savedTo:   TOKENS_FILE,
  errors:    results.errors,
}];
